const wins = $input.all().map(i => i.json);
const agencyCount = {};
wins.forEach(w => { const a = w.agency || 'Unknown'; agencyCount[a] = (agencyCount[a]||0)+1; });
const naicsCount = {};
wins.forEach(w => { const n = w.naics_code || 'Unknown'; naicsCount[n] = (naicsCount[n]||0)+1; });
const factorCount = {};
wins.forEach(w => {
  let factors = w.win_factors;
  if (!factors) return;
  if (typeof factors === 'string') factors = factors.replace(/^\{|\}$/g,'').split(',').map(f=>f.replace(/^"|"$/g,'').trim());
  if (Array.isArray(factors)) factors.forEach(f => { if(f) factorCount[f] = (factorCount[f]||0)+1; });
});
const displaced = wins.filter(w => w.incumbent_displaced === true || w.incumbent_displaced === 't').length;
const displacementRate = wins.length > 0 ? Math.round((displaced/wins.length)*100) : 0;
const topAgencies = Object.entries(agencyCount).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([a,c])=>({agency:a,wins:c}));
const topNaics = Object.entries(naicsCount).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([n,c])=>({naics:n,wins:c}));
const topFactors = Object.entries(factorCount).sort((a,b)=>b[1]-a[1]).slice(0,8).map(([f,c])=>({factor:f,count:c}));
const setAsideCount = {};
wins.forEach(w => { const s = w.set_aside || 'Unrestricted'; setAsideCount[s] = (setAsideCount[s]||0)+1; });
const sampleWins = wins.slice(0,5).map(w => ({ title: w.opportunity_title, agency: w.agency, value: w.contract_value, key_diff: w.key_differentiators }));
return [{ json: { total_wins: wins.length, displacement_rate: displacementRate, top_agencies: topAgencies, top_naics: topNaics, top_win_factors: topFactors, set_aside_breakdown: setAsideCount, sample_wins: sampleWins, analyzed_at: new Date().toISOString() } }];
